I also faced this bug and this issue helped me, thanks =)

So my solution was to monkeypatch the `addTable` method to avoid these bugs (without having to modify each call):
```js
const Worksheet = require('exceljs/lib/doc/worksheet.js');

let unnamedIndex = 0
const addTable = Worksheet.prototype.addTable
Worksheet.prototype.addTable = function (model) {

  let { name, rows } = model

  if (!name)
    name = 'unnamed' + (unnamedIndex++)

  if (rows.length < 1)
    rows = [['']]

  return addTable.call(this, {
    ...model,
    name,
    rows,
  })
}
```
